use distributed_inference::holographic_reconstruction::{
    ProjectionView, SovereignSieve, VoxelCoord,
};
use distributed_inference::pleromatic_frame::{
    MonsterPath, PleromaticFrame, PleromaticMediaType, SignalToken,
};
use std::fs;
use std::path::PathBuf;
use std::process::Command;

#[test]
fn test_gnexec_hello_world_handshake_e2e() {
    // 1. Save "Hello World" script.
    let ts_content = r#"
        function main(input) {
            console.log("hello:" + input.name);
            return 0;
        }
    "#;
    let ts_path = PathBuf::from("hello_test.ts");
    fs::write(&ts_path, ts_content).expect("Failed to write test TS file");

    // 2. Execute it via gnexec and capture fingerprint.
    // Use the absolute path or relative to project root.
    let gnexec_path = "./open-source/gnosis/polyglot/target/release/gnexec";

    // Check if gnexec exists before running.
    if !std::path::Path::new(gnexec_path).exists() {
        println!("skipping test: gnexec not found at {}", gnexec_path);
        return;
    }

    let output = Command::new(gnexec_path)
        .arg(&ts_path)
        .arg("--input-json")
        .arg(r#"{"name": "monster"}"#)
        .arg("--print-fingerprint")
        .output()
        .expect("Failed to execute gnexec");

    let stderr = String::from_utf8_lossy(&output.stderr);
    let stdout = String::from_utf8_lossy(&output.stdout);

    // 3. Verify execution output.
    assert!(stderr.contains("hello:monster"));

    // 4. Verify and parse topological fingerprint.
    // Stderr output matches: "[T, S, T, V, V]"
    let mut path = Vec::new();
    if let Some(start) = stderr.find('[') {
        if let Some(end) = stderr.find(']') {
            let tokens_str = &stderr[start + 1..end];
            for t in tokens_str.split(',') {
                match t.trim() {
                    "T" => path.push(SignalToken::T),
                    "S" => path.push(SignalToken::S),
                    "V" => path.push(SignalToken::V),
                    _ => {}
                }
            }
        }
    }

    assert!(!path.is_empty());
    assert_eq!(path[0], SignalToken::T);

    // 5. Verify it reconstructs into a 3D manifold.
    let mut sieve = SovereignSieve::new(40, 40, 40);
    let mut views = Vec::new();

    // Project the 1D path into 3D coords based on index.
    let active_coords: Vec<VoxelCoord> = path
        .iter()
        .enumerate()
        .map(|(i, _)| VoxelCoord {
            x: i as i32,
            y: i as i32,
            z: i as i32,
        })
        .collect();

    // Create 3 views of this path.
    for i in 0..3 {
        let angle = i as f32 * 2.0 * std::f32::consts::PI / 3.0;
        let mut frame_data = vec![0u8; 40 * 40];

        for coord in &active_coords {
            let (u, v) = distributed_inference::holographic_reconstruction::VirtualShutter::project(
                *coord,
                &ProjectionView {
                    view_id: "v".into(),
                    angle_rad: angle,
                    frame_data: Vec::new(),
                    width: 40,
                    height: 40,
                },
                VoxelCoord {
                    x: 40,
                    y: 40,
                    z: 40,
                },
            );
            if u < 40 && v < 40 {
                frame_data[v * 40 + u] = 255;
            }
        }

        views.push(ProjectionView {
            view_id: format!("v{}", i),
            angle_rad: angle,
            frame_data,
            width: 40,
            height: 40,
        });
    }

    sieve.reconstruct(&views);

    // At least one coordinate in the path should be verified.
    assert!(sieve.space.voxels.values().any(|v| v.is_path));

    // Cleanup
    let _ = fs::remove_file(ts_path);
}
